const mcps = msg.payload;
flow.set('mcp_states', {
    zone1: mcps[0] === 1 || mcps[0] === true,
    zone2: mcps[1] === 1 || mcps[1] === true,
    zone3: mcps[2] === 1 || mcps[2] === true
});
return null; // do not output immediately

const bells = msg.payload;
flow.set('bell_states', {
    zone1: bells[0] === 1 || bells[0] === true,
    zone2: bells[1] === 1 || bells[1] === true,
    zone3: bells[2] === 1 || bells[2] === true
});
return null; // do not output immediately

const registers = msg.payload; // raw array from modbus

// Get stored MCP and Bell state inputs from context (default false if not polled yet)
const mcps = flow.get('mcp_states') || { zone1: false, zone2: false, zone3: false };
const bells = flow.get('bell_states') || { zone1: false, zone2: false, zone3: false };

// Map Modbus Registers (Scaling values to match engineering units)
// HR 40001 (reg[0]) = Zone 1 Smoke level (0-5.00% scaled x100 in PLC, e.g., 125 -> 1.25)
// HR 40002 (reg[1]) = Zone 1 Temperature (0-120°C scaled x10 in PLC, e.g., 224 -> 22.4)
const z1_smoke = (registers[0] || 0) / 100;
const z1_temp = (registers[1] || 0) / 10;

// HR 40003 (reg[2]) = Zone 2 Smoke
// HR 40004 (reg[3]) = Zone 2 Temperature
const z2_smoke = (registers[2] || 0) / 100;
const z2_temp = (registers[3] || 0) / 10;

// HR 40005 (reg[4]) = Zone 3 Smoke
// HR 40006 (reg[5]) = Zone 3 Temperature
// HR 40007 (reg[6]) = Zone 3 Gas Concentration (Direct PPM reading, e.g., 15)
const z3_smoke = (registers[4] || 0) / 100;
const z3_temp = (registers[5] || 0) / 10;
const z3_gas = registers[6] || 0;

// Structure complete payload matching FGS-PRO Dashboard layout
msg.payload = {
    timestamp: Date.now(),
    zones: {
        zone1_server_room: {
            smoke_level: z1_smoke,
            temperature: z1_temp,
            manual_call_point: mcps.zone1,
            alarm_bell: bells.zone1
        },
        zone2_production: {
            smoke_level: z2_smoke,
            temperature: z2_temp,
            manual_call_point: mcps.zone2,
            alarm_bell: bells.zone2
        },
        zone3_battery_room: {
            smoke_level: z3_smoke,
            temperature: z3_temp,
            gas_level: z3_gas,
            manual_call_point: mcps.zone3,
            alarm_bell: bells.zone3
        }
    }
};

return msg;

const cmd = msg.payload.command;

// We will output to multiple pins based on command:
// Pin 1: Acknowledge Coil (Write to Coil 00010)
// Pin 2: Reset System Coil (Write to Coil 00011)

if (cmd === "ACKNOWLEDGE") {
    return [ { payload: true }, null ];
} else if (cmd === "RESET") {
    return [ null, { payload: true } ];
}

return null;
